package com.restaurantcraft.registry;
import com.restaurantcraft.RestaurantCraft; import com.restaurantcraft.blockentity.*; import net.minecraft.world.level.block.entity.BlockEntityType; import net.minecraftforge.registries.*; import net.minecraftforge.eventbus.api.IEventBus;
public class ModBlockEntities { public static final DeferredRegister<BlockEntityType<?>> BLOCK_ENTITIES=DeferredRegister.create(ForgeRegistries.BLOCK_ENTITY_TYPES,RestaurantCraft.MODID); public static final RegistryObject<BlockEntityType<RestaurantManagementBlockEntity>> RESTAURANT_MANAGEMENT=BLOCK_ENTITIES.register("restaurant_management",()->BlockEntityType.Builder.of(RestaurantManagementBlockEntity::new,ModBlocks.RESTAURANT_MANAGEMENT_BLOCK.get()).build(null)); public static final RegistryObject<BlockEntityType<RestaurantChairBlockEntity>> RESTAURANT_CHAIR=BLOCK_ENTITIES.register("restaurant_chair",()->BlockEntityType.Builder.of(RestaurantChairBlockEntity::new,ModBlocks.RESTAURANT_CHAIR.get()).build(null)); public static final RegistryObject<BlockEntityType<CookingDeviceBlockEntity>> COOKING_DEVICE=BLOCK_ENTITIES.register("cooking_device",()->BlockEntityType.Builder.of(CookingDeviceBlockEntity::new,ModBlocks.STEAMER.get(),ModBlocks.BOILING_POT.get(),ModBlocks.WOK.get(),ModBlocks.DRINK_MIXER.get()).build(null)); public static final RegistryObject<BlockEntityType<SinkBlockEntity>> SINK=BLOCK_ENTITIES.register("sink",()->BlockEntityType.Builder.of(SinkBlockEntity::new,ModBlocks.SINK.get()).build(null)); public static void register(IEventBus bus){BLOCK_ENTITIES.register(bus);} }
